  private static final byte[] privateKeyMlDsa87Seed = Hex.decode(PRIVATE_KEY_MLDSA87_SEED_HEX);
  private static final byte[] publicKeyMlDsa87 = Hex.decode(PUBLIC_KEY_MLDSA87_HEX);
  private static final byte[] messageMlDsa87 = Hex.decode(MESSAGE_MLDSA87_HEX);
  private static final byte[] noPrefixSignatureMlDsa87 = Hex.decode(SIGNATURE_MLDSA87_HEX);
  private static final byte[] tinkSignatureMlDsa87 =
      Hex.decode("0112345678" + SIGNATURE_MLDSA87_HEX);

  private static MlDsaPublicKey noPrefixMlDsa65PublicKey;
  private static MlDsaPrivateKey noPrefixMlDsa65PrivateKey;
  private static MlDsaPublicKey tinkMlDsa65PublicKey;
  private static MlDsaPrivateKey tinkMlDsa65PrivateKey;
  private static MlDsaPublicKey noPrefixMlDsa87PublicKey;
  private static MlDsaPrivateKey noPrefixMlDsa87PrivateKey;
  private static MlDsaPublicKey tinkMlDsa87PublicKey;
  private static MlDsaPrivateKey tinkMlDsa87PrivateKey;

  @BeforeClass
  public static void setUp() throws Exception {
    try {
      Conscrypt.checkAvailability();
      Security.addProvider(Conscrypt.newProvider());
    } catch (Throwable cause) {
      // If Conscrypt is not available, we verify that the primitive creation fails.
    }
    noPrefixMlDsa65PublicKey =
        MlDsaPublicKey.builder()
            .setParameters(NO_PREFIX_MLDSA65_PARAMS)
            .setSerializedPublicKey(Bytes.copyFrom(publicKeyMlDsa65))
            .build();
    noPrefixMlDsa65PrivateKey =
        MlDsaPrivateKey.createWithoutVerification(
            noPrefixMlDsa65PublicKey,
            SecretBytes.copyFrom(privateKeyMlDsa65Seed, InsecureSecretKeyAccess.get()));
    tinkMlDsa65PublicKey =
        MlDsaPublicKey.builder()
            .setParameters(TINK_MLDSA65_PARAMS)
            .setSerializedPublicKey(Bytes.copyFrom(publicKeyMlDsa65))
            .setIdRequirement(0x12345678)
            .build();
    tinkMlDsa65PrivateKey =
        MlDsaPrivateKey.createWithoutVerification(
            tinkMlDsa65PublicKey,
            SecretBytes.copyFrom(privateKeyMlDsa65Seed, InsecureSecretKeyAccess.get()));

    noPrefixMlDsa87PublicKey =
        MlDsaPublicKey.builder()
            .setParameters(NO_PREFIX_MLDSA87_PARAMS)
            .setSerializedPublicKey(Bytes.copyFrom(publicKeyMlDsa87))
            .build();
    noPrefixMlDsa87PrivateKey =
        MlDsaPrivateKey.createWithoutVerification(
            noPrefixMlDsa87PublicKey,
            SecretBytes.copyFrom(privateKeyMlDsa87Seed, InsecureSecretKeyAccess.get()));
    tinkMlDsa87PublicKey =
        MlDsaPublicKey.builder()
            .setParameters(TINK_MLDSA87_PARAMS)
            .setSerializedPublicKey(Bytes.copyFrom(publicKeyMlDsa87))
            .setIdRequirement(0x12345678)
            .build();
    tinkMlDsa87PrivateKey =
        MlDsaPrivateKey.createWithoutVerification(
            tinkMlDsa87PublicKey,
            SecretBytes.copyFrom(privateKeyMlDsa87Seed, InsecureSecretKeyAccess.get()));
  }

  @Test
  public void isSupported_conscryptAvailable_onAndroid_returnsFalse() throws Exception {
    // Currently Android doesn't support ML-DSA. This will change in the future. Once it's changed,
    // this test would need to be changed, as well as the SignatureConfigurationV1ConscryptTest
    // where the extra if's related to availability of Conscrypt for ML-DSA will become
    // unnecessary.
    Assume.assumeTrue(ConscryptUtil.providerOrNull() != null && Util.isAndroid());

    assertFalse(MlDsaSignConscrypt.isSupported());
    assertFalse(MlDsaVerifyConscrypt.isSupported());
  }

  @Test
  public void signAndVerify_noPrefix_mlDsa65() throws Exception {
    Assume.assumeTrue(MlDsaVerifyConscrypt.isSupported());

    PublicKeySign signer = MlDsaSignConscrypt.create(noPrefixMlDsa65PrivateKey);
    PublicKeyVerify verifier = MlDsaVerifyConscrypt.create(noPrefixMlDsa65PublicKey);

    byte[] signature = signer.sign(testData);

    assertThat(signature).hasLength(MLDSA65_SIGNATURE_BYTES);
    verifier.verify(signature, testData);
  }

  @Test
  public void signAndVerify_tinkPrefix_mlDsa65() throws Exception {
    Assume.assumeTrue(MlDsaVerifyConscrypt.isSupported());

    PublicKeySign signer = MlDsaSignConscrypt.create(tinkMlDsa65PrivateKey);
    PublicKeyVerify verifier = MlDsaVerifyConscrypt.create(tinkMlDsa65PublicKey);

    byte[] signature = signer.sign(testData);

    assertThat(signature).hasLength(5 + MLDSA65_SIGNATURE_BYTES);
    assertThat(Hex.encode(Arrays.copyOf(signature, 1))).isEqualTo("01");
    assertThat(Hex.encode(Arrays.copyOfRange(signature, 1, 5))).isEqualTo("12345678");
    verifier.verify(signature, testData);
  }

